int main() {
    Dog myDog("Sparky");
    myDog.makeSound();
    myDog.printDetails();

    std::cout << "\nChanging dog's name:" << std::endl;
    std::string tempName = "Max";
    myDog.setDogName(tempName);
    myDog.printDetails();

    std::cout << "\nDemonstrating outside function access restrictions:" << std::endl;
    std::cout << "Dog's name (via public getter): " << myDog.getDogName() << std::endl;
    std::cout << "Animal's name (via public getter): " << myDog.getAnimalNamePublic() << std::endl;

    return 0;
}
